 53→    /// <summary>
 54→    /// Provides extension methods for adding OnePortal Falcon services to the <see cref="IServiceCollection"/>.
 55→    /// </summary>
 56→    public static class OnePortalServiceCollectionExtension
 57→    {
 58→        /// <summary>
 59→        /// Adds OnePortal Falcon backend services for pure backend service.
 60→        /// </summary>
 61→        /// <param name="services">The service collection to add the services to.</param>
 62→        /// <param name="portalName">The name of the portal.</param>
 63→        public static void AddOnePortalFalconBackendServices(this IServiceCollection services, string portalName)
 64→        {
 65→            services.AddSingleton<IEnvironmentProperties, EnvironmentProperties>();
 66→            services.AddSingleton<ICredentialFactory>(sp => sp.GetService<IEnvironmentProperties>()!.Environment == EnvironmentEnum.DevMachine ? new DefaultCredentialFactory() : new OnePortalCredentialFactory());
 67→            services.AddSingleton<TokenCredential>(sp => sp.GetService<ICredentialFactory>()!.CreateTokenCredential());
 68→
 69→            services.AddMdmLogging(options => options.AddDefaultCounterRules(
 70→                $"Microsoft.Falcon.{portalName}",
 71→                "BingIndexServeGalaxy",
 72→                portalName));
 73→
 74→            services.AddFalcon();
 75→            services.AddMdsLogging();
 76→        }
 77→
 78→        /// <summary>
 79→        /// Adds OnePortal Falcon services for web portal.
 80→        /// </summary>
 81→        /// <param name="services">The service collection to add the services to.</param>
 82→        /// <param name="portalName">The name of the portal.</param>
 83→        /// <param name="oneportalConfig">oneportalconfig.</param>
 84→        public static void AddOnePortalFalconServicesSPA(this IServiceCollection services, string portalName, OnePortalConfig oneportalConfig)
 85→        {
 86→            services.AddSingleton<IEnvironmentProperties, EnvironmentProperties>();
 87→            services.AddSingleton<ICredentialFactory>(sp => sp.GetService<IEnvironmentProperties>()!.Environment == EnvironmentEnum.DevMachine ? new DefaultCredentialFactory() : new OnePortalCredentialFactory());
 88→            services.AddSingleton<TokenCredential>(sp => sp.GetService<ICredentialFactory>()!.CreateTokenCredential());
 89→
 90→            services.AddMdmLogging(options => options.AddDefaultCounterRules(
 91→                $"Microsoft.Falcon.{portalName}",
 92→                "BingIndexServeGalaxy",
 93→                portalName));
 94→
 95→            services.AddControllers();
 96→
 97→            // Learn more about configuring Swagger/OpenAPI at https://aka.ms/aspnetcore/swashbuckle
 98→            services.AddEndpointsApiExplorer();
 99→            services.AddSwaggerGen();
100→
101→            // Start workaround
102→            // We can't call services.AddFalcon() here, and we just go into the function and pick what can work to add here
103→            // the two comment out lines are what can't workswell
104→            // services.AddFalcon();
105→            services.AddMvcCore();
106→            services.AddTracing();
107→            services.Configure(delegate(LoggerFilterOptions o)
108→            {
109→                o.MinLevel = Microsoft.Extensions.Logging.LogLevel.Information;
110→            });
111→            services.AddFalconLogging();
112→            if (RuntimeInformation.IsOSPlatform(OSPlatform.Windows))
113→            {
114→                services.AddMdsLogging();
115→                services.AddDotNetCoreCounters();
116→            }
117→
118→            services.AddCountersInitialization();
119→            services.AddKeepalive();
120→            services.AddFalconWebCore();
121→            services.AddMdsLogging();
122→
123→            // We can't use DI in this function as DI is not setup before this service is called
124→#pragma warning disable ASP0000 // Do not call 'IServiceCollection.BuildServiceProvider' in 'ConfigureServices'
125→            var serviceProvider = services.BuildServiceProvider();
126→#pragma warning restore ASP0000 // Do not call 'IServiceCollection.BuildServiceProvider' in 'ConfigureServices'
127→            var config = serviceProvider.GetService<IConfiguration>();
128→            var webHostEnv = serviceProvider.GetService<IWebHostEnvironment>();
129→            var falconCredentialFactory = serviceProvider.GetService<ICredentialFactory>();
130→            OnePortalServiceCollectionExtension.AddFalconAADAuthentication(webHostEnv!, services, config!, falconCredentialFactory!, oneportalConfig);
131→
132→            services.AddControllers().AddNewtonsoftJson(options =>
133→            {
134→                options.SerializerSettings.ContractResolver = new DefaultContractResolver();
135→            });
136→            services.Configure<WarmupOptions>(opts =>
137→            {
138→                opts.WarmupTimeout = TimeSpan.FromMinutes(1);
139→                opts.ContinueOnWarmupError = false;
140→                opts.ExecuteInParallel = false;
141→            });
142→            services.AddWarmup();
143→            services.AddTransient<IWarmupTask, ServiceWarmupTask>();
144→
145→            var certPath = Environment.GetEnvironmentVariable("HTTPS_CERTIFICATE_FILE_PATH");
146→            if (!string.IsNullOrEmpty(certPath))
147→            {
148→                services.Configure<Microsoft.Falcon.Loader.DynamicHttpsCertificateOptions>(options =>
149→                {
150→                    options.EnableDynamicHttpsCertificateRefresh = true;
151→                    options.HttpsCertificateFilePath = certPath;
152→                });
153→            }
154→        }
