165→            AddOnePortalFalconBackendServices(services, portalName);
166→
167→            // We can't use DI in this function as DI is not setup before this service is called
168→#pragma warning disable ASP0000 // Do not call 'IServiceCollection.BuildServiceProvider' in 'ConfigureServices'
169→            var serviceProvider = services.BuildServiceProvider();
170→#pragma warning restore ASP0000 // Do not call 'IServiceCollection.BuildServiceProvider' in 'ConfigureServices'
171→            var config = serviceProvider.GetService<IConfiguration>();
172→            var webHostEnv = serviceProvider.GetService<IWebHostEnvironment>();
173→            var falconCredentialFactory = serviceProvider.GetService<ICredentialFactory>();
174→            AddFalconAADAuthentication(webHostEnv!, services, config!, falconCredentialFactory!, oneportalConfig);
175→
176→            services.AddControllers().AddNewtonsoftJson(options =>
177→            {
178→                options.SerializerSettings.ContractResolver = new DefaultContractResolver();
179→            });
180→            services.Configure<WarmupOptions>(opts =>
181→            {
182→                opts.WarmupTimeout = TimeSpan.FromMinutes(1);
183→                opts.ContinueOnWarmupError = false;
184→                opts.ExecuteInParallel = false;
185→            });
186→            services.AddWarmup();
187→            services.AddTransient<IWarmupTask, ServiceWarmupTask>();
188→
189→            if (!oneportalConfig.EnableProxy)
190→            {
191→                ConfigureSwagger(services);
192→                services.AddRazorPages().AddMvcOptions(options =>
193→                {
194→                    var policy = new AuthorizationPolicyBuilder()
195→                                  .RequireAuthenticatedUser()
196→                                  .Build();
197→                    options.Filters.Add(new AuthorizeFilter(policy));
198→                }).AddMicrosoftIdentityUI();
199→
200→                // In production, the React files will be served from this directory
201→                services.AddSpaStaticFiles(configuration =>
202→                {
203→                    configuration.RootPath = "ClientApp/build";
204→                });
205→            }
206→
207→            var certPath = Environment.GetEnvironmentVariable("HTTPS_CERTIFICATE_FILE_PATH");
208→            if (!string.IsNullOrEmpty(certPath))
209→            {
210→                services.Configure<Microsoft.Falcon.Loader.DynamicHttpsCertificateOptions>(options =>
211→                {
212→                    options.EnableDynamicHttpsCertificateRefresh = true;
213→                    options.HttpsCertificateFilePath = certPath;
214→                });
215→            }
216→        }
