218→        private static void ConfigureSwagger(IServiceCollection services)
219→        {
220→            services.AddSwaggerGen(c =>
221→            {
222→                // Define the OAuth2.0 scheme that's in use (i.e. Implicit Flow)
223→                c.AddSecurityDefinition("oauth2", new OpenApiSecurityScheme
224→                {
225→                    Type = SecuritySchemeType.OAuth2,
226→                    Flows = new OpenApiOAuthFlows
227→                    {
228→                        Implicit = new OpenApiOAuthFlow
229→                        {
230→                            AuthorizationUrl = new Uri($"https://login.microsoftonline.com/{LibOnePortal.Secret.Constants.MsftTenentId}/oauth2/v2.0/authorize"),
231→                            TokenUrl = new Uri($"https://login.microsoftonline.com/{LibOnePortal.Secret.Constants.MsftTenentId}/oauth2/v2.0/authorize"),
232→                            Scopes = new Dictionary<string, string>
233→                            {
234→                                { "User.Read", "Access all endpoints for this app" },
235→                            },
236→                        },
237→                    },
238→                });
239→
240→                c.AddSecurityRequirement(new OpenApiSecurityRequirement
241→                {
242→                    {
243→                        new OpenApiSecurityScheme
244→                        {
245→                            Reference = new OpenApiReference
246→                            {
247→                                Type = ReferenceType.SecurityScheme,
248→                                Id = "oauth2",
249→                            },
250→                        },
251→                        new string[] { "User.Read" }
252→                    },
253→                });
254→            });
255→        }
