 7→namespace CodeXCore.UtilizationMetricCollection
 8→{
 9→    using System;
10→    using System.Threading;
11→    using System.Threading.Tasks;
12→    using CodeXCore.UtilizationMetricCollection.Counter;
13→    using Microsoft.Extensions.DependencyInjection;
14→    using Microsoft.Extensions.Hosting;
15→    using Microsoft.Extensions.Logging;
16→
17→    /// <summary>
18→    /// Singleton background service that periodically delegates to a scoped
19→    /// <see cref="UtilizationMetricCollector"/> instance to fetch utilization data,
20→    /// build metrics tables, and emit MDM counters.
21→    /// </summary>
22→    public sealed class UtilizationMetricBackgroundService : BackgroundService
23→    {
24→        private const int SleepIntervalInMs = 1000 * 60 * 15; // 15 min
25→
26→        private readonly IServiceProvider serviceProvider;
27→        private readonly ILogger<UtilizationMetricBackgroundService> logger;
28→        private readonly IUtilizationCounterManager counterManager;
29→
30→        private volatile UtilizationMetricCollectionResult lastResult = new();
31→
32→        /// <summary>
33→        /// Initializes a new instance of the <see cref="UtilizationMetricBackgroundService"/> class.
34→        /// </summary>
35→        /// <param name="serviceProvider">The service provider.</param>
36→        /// <param name="logger">The logger.</param>
37→        /// <param name="counterManager">The utilization counter manager.</param>
38→        public UtilizationMetricBackgroundService(
39→            IServiceProvider serviceProvider,
40→            ILogger<UtilizationMetricBackgroundService> logger,
41→            IUtilizationCounterManager counterManager)
42→        {
43→            this.serviceProvider = serviceProvider ?? throw new ArgumentNullException(nameof(serviceProvider));
44→            this.logger = logger ?? throw new ArgumentNullException(nameof(logger));
45→            this.counterManager = counterManager ?? throw new ArgumentNullException(nameof(counterManager));
46→        }
47→
48→        /// <inheritdoc/>
49→        protected override async Task ExecuteAsync(CancellationToken stoppingToken)
50→        {
51→            this.logger.LogInformation("UtilizationMetricBackgroundService started.");
52→
53→            while (!stoppingToken.IsCancellationRequested)
54→            {
55→                try
56→                {
57→                    using var scope = this.serviceProvider.CreateScope();
58→                    var collector = scope.ServiceProvider.GetRequiredService<UtilizationMetricCollector>();
59→                    this.lastResult = await collector.CollectAsync(stoppingToken);
60→                    this.counterManager.EmitAll(this.lastResult);
61→                    this.logger.LogInformation("UtilizationMetricBackgroundService emitted MDM counters for all tables.");
62→                }
63→                catch (Exception ex)
64→                {
65→                    this.logger.LogError(ex, "Error in UtilizationMetricBackgroundService.");
66→                    throw;
67→                }
68→
69→                try
70→                {
71→                    await Task.Delay(SleepIntervalInMs, stoppingToken);
72→                }
73→                catch (TaskCanceledException)
74→                {
75→                    break;
76→                }
77→            }
78→
79→            this.logger.LogInformation("UtilizationMetricBackgroundService stopped.");
80→        }
81→    }
82→}
